import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import Header from '../../components/Header';
import Sidebar from '../../components/Sidebar';
import '../../styles/storekeeper/storekeeper-alerts.css';
import api from '../../services/api';

const StorekeeperAlerts = () => {
  const { user } = useAuth();
  const [alerts, setAlerts] = useState([]);
  const [filteredAlerts, setFilteredAlerts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [sortBy, setSortBy] = useState('current_balance');
  const [sortOrder, setSortOrder] = useState('asc');

  useEffect(() => {
    fetchLowStockAlerts();
  }, []);

  useEffect(() => {
    sortAlerts();
  }, [alerts, sortBy, sortOrder]);

  const fetchLowStockAlerts = async () => {
    try {
      setLoading(true);
      const res = await api.get('/inventory/alerts/low-stock');
      setAlerts(res.data?.data || []);
      setError(null);
    } catch (err) {
      console.error('Lỗi khi tải cảnh báo:', err);
      setError('Không thể tải danh sách cảnh báo');
    } finally {
      setLoading(false);
    }
  };

  const sortAlerts = () => {
    let sorted = [...alerts];

    sorted.sort((a, b) => {
      let aValue, bValue;

      switch (sortBy) {
        case 'current_balance':
          aValue = parseFloat(a.current_balance || 0);
          bValue = parseFloat(b.current_balance || 0);
          break;
        case 'min_quantity':
          aValue = parseFloat(a.min_quantity || 0);
          bValue = parseFloat(b.min_quantity || 0);
          break;
        case 'deficit':
          aValue = parseFloat(a.min_quantity || 0) - parseFloat(a.current_balance || 0);
          bValue = parseFloat(b.min_quantity || 0) - parseFloat(b.current_balance || 0);
          break;
        case 'item_name':
          aValue = a.item_name.toLowerCase();
          bValue = b.item_name.toLowerCase();
          break;
        default:
          aValue = a.current_balance;
          bValue = b.current_balance;
      }

      if (sortOrder === 'asc') {
        return aValue < bValue ? -1 : 1;
      } else {
        return aValue > bValue ? -1 : 1;
      }
    });

    setFilteredAlerts(sorted);
  };

  const handleSort = (column) => {
    if (sortBy === column) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(column);
      setSortOrder('asc');
    }
  };

  const getUrgencyLevel = (current, min) => {
    const ratio = parseFloat(current || 0) / parseFloat(min || 1);
    if (ratio === 0) return 'critical';
    if (ratio <= 0.25) return 'urgent';
    if (ratio <= 0.5) return 'high';
    return 'medium';
  };

  const getUrgencyLabel = (level) => {
    const labels = {
      critical: '🔴 Cực cấp',
      urgent: '🟠 Rất cấp',
      high: '🟡 Cao',
      medium: '🟢 Trung bình',
    };
    return labels[level] || level;
  };

  const getDeficitQuantity = (current, min) => {
    return Math.max(0, parseFloat(min || 0) - parseFloat(current || 0));
  };

  const getReorderQuantity = (min, max, current) => {
    // Suggest reordering to max level
    return Math.max(0, parseFloat(max || min) - parseFloat(current || 0));
  };

  return (
    <div className="storekeeper-alerts">
      <Header />
      <div className="storekeeper-alerts__container">
        <Sidebar />
        <main className="storekeeper-alerts__content">
          <div className="storekeeper-alerts__header">
            <h1>⚠️ Cảnh báo tồn kho thấp</h1>
            <p>Danh sách sản phẩm cần nhập lại</p>
          </div>

          {error && (
            <div className="storekeeper-alerts__error">
              <p>{error}</p>
              <button onClick={fetchLowStockAlerts}>Thử lại</button>
            </div>
          )}

          {/* Summary Stats */}
          <div className="storekeeper-alerts__stats">
            <div className="storekeeper-alerts__stat-card">
              <span className="stat-card__icon">🔴</span>
              <div className="stat-card__content">
                <h3>Cực cấp</h3>
                <p className="stat-card__value">
                  {filteredAlerts.filter(
                    (a) => getUrgencyLevel(a.current_balance, a.min_quantity) === 'critical'
                  ).length}
                </p>
              </div>
            </div>

            <div className="storekeeper-alerts__stat-card">
              <span className="stat-card__icon">🟠</span>
              <div className="stat-card__content">
                <h3>Rất cấp</h3>
                <p className="stat-card__value">
                  {filteredAlerts.filter(
                    (a) => getUrgencyLevel(a.current_balance, a.min_quantity) === 'urgent'
                  ).length}
                </p>
              </div>
            </div>

            <div className="storekeeper-alerts__stat-card">
              <span className="stat-card__icon">🟡</span>
              <div className="stat-card__content">
                <h3>Cao</h3>
                <p className="stat-card__value">
                  {filteredAlerts.filter(
                    (a) => getUrgencyLevel(a.current_balance, a.min_quantity) === 'high'
                  ).length}
                </p>
              </div>
            </div>

            <div className="storekeeper-alerts__stat-card">
              <span className="stat-card__icon">📦</span>
              <div className="stat-card__content">
                <h3>Tổng sản phẩm cảnh báo</h3>
                <p className="stat-card__value">{filteredAlerts.length}</p>
              </div>
            </div>
          </div>

          {/* Sort Options */}
          <div className="storekeeper-alerts__controls">
            <label>Sắp xếp theo:</label>
            <div className="storekeeper-alerts__sort-buttons">
              <button
                className={`storekeeper-alerts__sort-btn ${sortBy === 'current_balance' ? 'active' : ''}`}
                onClick={() => handleSort('current_balance')}
              >
                Tồn kho {sortBy === 'current_balance' && (sortOrder === 'asc' ? '↑' : '↓')}
              </button>
              <button
                className={`storekeeper-alerts__sort-btn ${sortBy === 'deficit' ? 'active' : ''}`}
                onClick={() => handleSort('deficit')}
              >
                Thiếu {sortBy === 'deficit' && (sortOrder === 'asc' ? '↑' : '↓')}
              </button>
              <button
                className={`storekeeper-alerts__sort-btn ${sortBy === 'item_name' ? 'active' : ''}`}
                onClick={() => handleSort('item_name')}
              >
                Tên sản phẩm {sortBy === 'item_name' && (sortOrder === 'asc' ? '↑' : '↓')}
              </button>
            </div>
          </div>

          {/* Alerts Table */}
          {loading ? (
            <div className="storekeeper-alerts__loading">Đang tải...</div>
          ) : (
            <div className="storekeeper-alerts__table-wrapper">
              {filteredAlerts.length > 0 ? (
                <table className="storekeeper-alerts__table">
                  <thead>
                    <tr>
                      <th>Độ ưu tiên</th>
                      <th>Mã sản phẩm</th>
                      <th>Tên sản phẩm</th>
                      <th>Danh mục</th>
                      <th>Tồn kho</th>
                      <th>Tối thiểu</th>
                      <th>Thiếu</th>
                      <th>Đơn giá</th>
                      <th>Chi phí nhập lại</th>
                      <th>Đơn vị</th>
                      <th>Gợi ý</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredAlerts.map((alert) => {
                      const urgency = getUrgencyLevel(alert.current_balance, alert.min_quantity);
                      const deficit = getDeficitQuantity(alert.current_balance, alert.min_quantity);
                      const reorder = getReorderQuantity(alert.min_quantity, alert.max_quantity, alert.current_balance);
                      const restockCost = deficit * parseFloat(alert.unit_price || 0);

                      return (
                        <tr key={alert.item_id} className={`storekeeper-alerts__row--${urgency}`}>
                          <td className="storekeeper-alerts__urgency">
                            <span className={`storekeeper-alerts__badge storekeeper-alerts__badge--${urgency}`}>
                              {getUrgencyLabel(urgency)}
                            </span>
                          </td>
                          <td className="storekeeper-alerts__code">{alert.item_code}</td>
                          <td>{alert.item_name}</td>
                          <td>{alert.category_name}</td>
                          <td className="storekeeper-alerts__current">
                            <strong>{parseFloat(alert.current_balance).toFixed(2)}</strong>
                          </td>
                          <td className="storekeeper-alerts__minimum">
                            {parseFloat(alert.min_quantity).toFixed(2)}
                          </td>
                          <td className="storekeeper-alerts__deficit">
                            <strong style={{ color: '#ef4444' }}>
                              -{deficit.toFixed(2)}
                            </strong>
                          </td>
                          <td className="storekeeper-alerts__price">
                            {parseFloat(alert.unit_price || 0).toLocaleString('vi-VN')} VNĐ
                          </td>
                          <td className="storekeeper-alerts__cost">
                            {restockCost.toLocaleString('vi-VN')} VNĐ
                          </td>
                          <td>{alert.unit}</td>
                          <td className="storekeeper-alerts__suggestion">
                            <div className="storekeeper-alerts__suggestion-text">
                              Nhập {reorder.toFixed(2)} để đạt tối đa
                            </div>
                            <button className="storekeeper-alerts__action-btn">
                              🛒 Đặt mua
                            </button>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              ) : (
                <div className="storekeeper-alerts__empty">
                  <p>✓ Tất cả sản phẩm đều có tồn kho đủ</p>
                </div>
              )}
            </div>
          )}

          {/* Legend */}
          <div className="storekeeper-alerts__legend">
            <h3>Giải thích mức độ ưu tiên:</h3>
            <div className="storekeeper-alerts__legend-items">
              <div className="legend-item">
                <span className="legend-color" style={{ backgroundColor: '#dc2626' }}></span>
                <span>🔴 <strong>Cực cấp:</strong> Tồn kho = 0</span>
              </div>
              <div className="legend-item">
                <span className="legend-color" style={{ backgroundColor: '#ea580c' }}></span>
                <span>🟠 <strong>Rất cấp:</strong> Tồn kho ≤ 25% mục tiêu</span>
              </div>
              <div className="legend-item">
                <span className="legend-color" style={{ backgroundColor: '#f59e0b' }}></span>
                <span>🟡 <strong>Cao:</strong> Tồn kho ≤ 50% mục tiêu</span>
              </div>
              <div className="legend-item">
                <span className="legend-color" style={{ backgroundColor: '#84cc16' }}></span>
                <span>🟢 <strong>Trung bình:</strong> Tồn kho > 50% mục tiêu</span>
              </div>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
};

export default StorekeeperAlerts;
